@keyframes style_element-slide-in__GFhZL { 
  0% { opacity: 0; transform: translateY(1.875rem); }
  50% { opacity: 0.7; }
  100% { opacity: 1; transform: translateY(0px); }
}

@keyframes style_sparks__a0ehT { 
  0% { opacity: 0; transform: translate(0px); }
  1% { opacity: 1; transform: translateY(-20%); }
  40% { opacity: 1; }
  100% { opacity: 0; transform: translateY(-100%); }
}

@keyframes style_gradient1__zln49 { 
  0% { opacity: 0; transform: translate(-55%, -39%); }
