  100% { opacity: 0; transform: translate(-55%, 39%); }
}

@keyframes style_gradient2__zZKKS { 
  0% { opacity: 0; transform: translate(-55%, -39%); }
  50% { opacity: 1; }
  100% { opacity: 0; transform: translate(-55%, 39%); }
}

@keyframes style_gradient3__GQFN0 { 
  0% { opacity: 0; transform: translate(55%, -39%); }
  50% { opacity: 1; }
  100% { opacity: 0; transform: translate(55%, 39%); }
}

@keyframes style_gradient4__NRvXt { 
  0% { opacity: 0; transform: translate(55%, -39%); }
  50% { opacity: 1; }
  100% { opacity: 0; transform: translate(55%, 39%); }
}

@keyframes style_sparkL__hYFlI { 
  0% { opacity: 1; }
  100% { opacity: 0.8; }
}

@keyframes style_sparkM__s6qoZ { 
  0% { opacity: 1; }
  100% { opacity: 0.6; }
}

@keyframes style_sparkS__hnqXn { 
  0% { opacity: 1; }
  100% { opacity: 0.4; }
}

@keyframes style_sparkHover__Bh23P { 
  0% { transform: scale(1); }
  50% { transform: scale(1.5); }
  100% { transform: scale(1); }
}

@keyframes cursor_talking__IiQ96 { 
  0%, 100% { transform: scale(1); }
  20%, 5%, 85% { transform: scale(1.15); }
  15%, 30%, 55%, 75%, 90% { transform: scale(1.05); }
  35%, 45%, 60%, 70% { transform: scale(1.2); }
  40%, 67%, 95% { transform: scale(1.1); }
  100% { transform: scale(1); }
}

@keyframes style_title-slide-in__C7mxd { 
  0% { opacity: 0; transform: translateY(2.5rem) rotateX(-25deg); }
  100% { opacity: 1; transform: translateY(0px) rotateX(0deg); }
}

@keyframes style_parallax__W5YVq { 
  0% { transform: translateY(3.125rem); }
  100% { transform: translateY(-3.125rem); }
}

@keyframes style_element-slide-in__kJVUM { 
  0% { opacity: 0; transform: translateY(1.875rem); }
  50% { opacity: 0.7; }
  100% { opacity: 1; transform: translateY(0px); }
}

@keyframes style_pulse__SA_Tq { 
  0% { opacity: 0.3; }
  40% { opacity: 1; }
  50% { opacity: 1; }
  90% { opacity: 0.3; }
  100% { opacity: 0.3; }
}

@keyframes style_cursor-1__ohwHl { 
  0% { transform: translate(-100px, 20px); }
  10% { transform: translate(0px); }
  25% { transform: translate(0px); }
  32% { transform: translate(-50px, 60px); }
  37% { transform: translate(-50px, 60px); }
  48% { transform: translate(-40px); }
  60% { transform: translate(-40px); }
  70% { transform: translate(-20px, 50px); }
  80% { transform: translate(-20px, 50px); }
  90% { transform: translate(-100px, 20px); }
  100% { transform: translate(-100px, 20px); }
}

@keyframes style_cursor-2__CyjkC { 
  0% { transform: translate(150px, 50px) scale(1); }
  80% { transform: translate(0px) scale(1); }
  84% { transform: translate(0px) scale(0.85); }
  100% { transform: translate(0px) scale(1); }
}

@keyframes style_cursor-3__lr_FD { 
  0% { transform: translate(100px, 30px); }
  10% { transform: translate(0px); }
  25% { transform: translate(0px); }
  32% { transform: translate(20px, -50px); }
  37% { transform: translate(20px, -50px); }
  48% { transform: translate(40px, 20px); }
  60% { transform: translate(40px, 20px); }
  70% { transform: translate(70px, -30px); }
  80% { transform: translate(70px, -30px); }
  90% { transform: translate(100px, 30px); }
  100% { transform: translate(100px, 30px); }
}

@keyframes intercom-lightweight-app-launcher { 
  0% { opacity: 0; transform: scale(0.5); }
  100% { opacity: 1; transform: scale(1); }
}

@keyframes intercom-lightweight-app-gradient { 
  0% { opacity: 0; }
  100% { opacity: 1; }
}

@keyframes intercom-lightweight-app-messenger { 
  0% { opacity: 0; transform: scale(0); }
  40% { opacity: 1; }
  100% { transform: scale(1); }
}
